// Normalize payload from any capture source (form, missed call, DM).
const raw = items[0].json.body || items[0].json;
const payload = {
  org_id: raw.org_id || raw.orgId || null,
  source: raw.source || 'web_form',
  name: (raw.name || raw.full_name || '').trim(),
  phone: (raw.phone || raw.phone_number || '').replace(/[^+0-9]/g, ''),
  email: (raw.email || '').toLowerCase(),
  message: raw.message || raw.notes || raw.body || '',
  vertical_hint: raw.vertical || raw.service_type || null,
  received_at: new Date().toISOString()
};
if (!payload.org_id) {
  throw new Error('org_id is required on every inbound lead payload');
}
return [{ json: payload }];

