// Parse Claude's JSON response and merge with the original lead payload.
const resp = items[0].json;
const text = (resp.content && resp.content[0] && resp.content[0].text) || '{}';
let classification;
try {
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  classification = JSON.parse(text.slice(start, end + 1));
} catch (e) {
  classification = { vertical: 'other', intent_score: 0, urgency: 'unknown', budget_signal: 'unknown', quality_reason: 'parse_failed', recommended_response: 'Operator review needed.' };
}
const lead = $('Normalize Payload').first().json;
return [{ json: { ...lead, ...classification, classified_at: new Date().toISOString() } }];

